package com.example.paymentmodule.security

import android.content.Context
import android.content.SharedPreferences
import androidx.security.crypto.EncryptedSharedPreferences
import androidx.security.crypto.MasterKey
import com.example.paymentmodule.data.model.TransactionDetails
import com.example.paymentmodule.data.model.WalletBalance
import com.google.gson.Gson
import com.google.gson.reflect.TypeToken
import java.lang.reflect.Type

class SecurePreferencesManager(context: Context) {

    private val gson = Gson()
    private val masterKeyAlias = MasterKey.Builder(context)
        .setKeyScheme(MasterKey.KeyScheme.AES256_GCM)
        .build()

    private val sharedPreferences: SharedPreferences by lazy {
        EncryptedSharedPreferences.create(
            context,
            "secure_payment_prefs",
            masterKeyAlias,
            EncryptedSharedPreferences.PrefKeyEncryptionScheme.AES256_SIV,
            EncryptedSharedPreferences.PrefValueEncryptionScheme.AES256_GCM
        )
    }

    // Wallet Balance
    fun saveWalletBalance(balance: WalletBalance) {
        sharedPreferences.edit().putString(KEY_WALLET_BALANCE, gson.toJson(balance)).apply()
    }

    fun getWalletBalance(): WalletBalance? {
        val json = sharedPreferences.getString(KEY_WALLET_BALANCE, null)
        return json?.let { gson.fromJson(it, WalletBalance::class.java) }
    }

    // Transaction History
    fun addTransaction(transaction: TransactionDetails) {
        val currentHistory = getTransactionHistory().toMutableList()
        currentHistory.add(0, transaction) // Add to the beginning for chronological order
        sharedPreferences.edit().putString(KEY_TRANSACTION_HISTORY, gson.toJson(currentHistory)).apply()
    }

    fun getTransactionHistory(): List<TransactionDetails> {
        val json = sharedPreferences.getString(KEY_TRANSACTION_HISTORY, null)
        val type: Type = object : TypeToken<List<TransactionDetails>>() {}.type
        return json?.let { gson.fromJson(it, type) } ?: emptyList()
    }

    // Other sensitive settings if needed
    fun saveLastKnownUserId(userId: String) {
        sharedPreferences.edit().putString(KEY_LAST_KNOWN_USER_ID, userId).apply()
    }

    fun getLastKnownUserId(): String? {
        return sharedPreferences.getString(KEY_LAST_KNOWN_USER_ID, null)
    }

    fun clearAllSecureData() {
        sharedPreferences.edit().clear().apply()
    }

    companion object {
        private const val KEY_WALLET_BALANCE = "wallet_balance"
        private const val KEY_TRANSACTION_HISTORY = "transaction_history"
        private const val KEY_LAST_KNOWN_USER_ID = "last_known_user_id"
    }
}

