package com.example.paymentmodule.wallet

import com.example.paymentmodule.PaymentResult
import com.example.paymentmodule.data.model.TransactionDetails
import com.example.paymentmodule.data.model.TransactionStatus
import com.example.paymentmodule.data.model.TransactionType
import com.example.paymentmodule.data.model.WalletBalance
import com.example.paymentmodule.gateway.PaymentGatewayClient
import com.example.paymentmodule.security.SecurePreferencesManager
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.withContext
import java.util.UUID

class WalletManager(
    private val securePreferencesManager: SecurePreferencesManager,
    private val paymentGatewayClient: PaymentGatewayClient,
    private val currentUserId: String // User ID should be provided by your auth system
) {

    private val _walletBalance = MutableStateFlow(
        securePreferencesManager.getWalletBalance() ?: WalletBalance(0, "USD", System.currentTimeMillis())
    )
    val walletBalance: StateFlow<WalletBalance> = _walletBalance.asStateFlow()

    init {
        // Load initial balance on creation
        _walletBalance.value = securePreferencesManager.getWalletBalance()
            ?: WalletBalance(0, "USD", System.currentTimeMillis())
    }

    // Call this if the user logs in/out to ensure correct data
    fun refreshForUser(newUserId: String) {
        if (this.currentUserId != newUserId) {
            // In a real app, you might want to fetch user-specific balance from backend here
            // For now, simply reset local balance for new user (or load their specific data)
            _walletBalance.value = securePreferencesManager.getWalletBalance()
                ?: WalletBalance(0, "USD", System.currentTimeMillis())
        }
    }

    // Add funds to the local wallet after a successful payment (e.g., via token, IAP)
    suspend fun addFundsLocally(amount: Long, currency: String, description: String): PaymentResult<WalletBalance> = withContext(Dispatchers.Default) {
        if (amount <= 0) {
            return@withContext PaymentResult.Error("Amount must be positive.")
        }

        val current = _walletBalance.value
        if (current.currency != currency) {
            // Handle currency conversion or enforce single currency
            return@withContext PaymentResult.Error("Currency mismatch. Expected ${current.currency}, got $currency.")
        }

        val newBalance = current.copy(
            amount = current.amount + amount,
            lastUpdated = System.currentTimeMillis()
        )
        securePreferencesManager.saveWalletBalance(newBalance)
        _walletBalance.value = newBalance

        // Record this as a successful add funds transaction
        val transaction = TransactionDetails(
            transactionId = UUID.randomUUID().toString(),
            amount = amount,
            currency = currency,
            type = TransactionType.WALLET_ADD